content:
{
  "grammar": [
    {
      "pattern": "Subject + 喜歡 / 不喜歡 + Object",
      "structure": ["Subject", "喜歡/不喜歡", "Object"],
      "explanation_en": "Use 喜歡 to express liking, and 不喜歡 to express disliking. The object can be a noun, verb phrase, or clause.",
      "title": "Expressing Likes and Dislikes with 喜歡 / 不喜歡",
      "meaning": "To say you like or dislike something",
      "when_to_use": ["When stating a preference for food, drinks, activities, or people", "When answering a question about what you like or dislike"],
      "when_not_to_use": ["When comparing two items (use 比較喜歡 instead)", "When asking for a choice between options (use 還是 instead)"],
      "pragmatic_notes": "In Taiwan, 不喜歡 is direct but polite; for stronger dislike, use 不太喜歡 (don't really like) to soften. Avoid 討厭 (hate) in casual conversation unless very close.",
      "word_order_notes": "Subject always comes first, then 喜歡/不喜歡, then the object. No additional particles needed.",
      "english_contrast": "English uses 'like/don't like' with same structure, but Chinese doesn't use 'to' before verbs (e.g., 'I like eat' is correct in Chinese: 我喜歡吃).",
      "korean_contrast": "Korean uses '좋아하다/싫어하다' with object particle '을/를', while Chinese uses no particle. Korean also has honorifics (좋아해요), but Chinese 喜歡 is neutral.",
      "negative_examples": [
        {
          "text": "我喜歡不咖啡。",
          "error": "不 must come before 喜歡, not after. Correct: 我不喜歡咖啡。"
        },
        {
          "text": "我喜歡咖啡不。",
          "error": "不 cannot be placed at the end of the sentence. Correct: 我不喜歡咖啡。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我喜歡很咖啡。",
          "error": "很 cannot modify 咖啡 directly. Use 很喜歡咖啡 (really like coffee) or 咖啡很好喝 (coffee is tasty)."
        },
        {
          "text": "我不喜歡喝咖啡嗎？",
          "error": "嗎 is for yes/no questions, but 不喜歡 already negates. For a question, use 你喜歡喝咖啡嗎？"
        }
      ],
      "transformation_drills": ["Change '我喜歡喝茶' to negative.", "Change '他不喜歡吃辣' to affirmative."],
      "production_drills": ["Say you like 珍珠奶茶.", "Say you don't like 牛肉麵."],
      "common_error_patterns": ["Placing 不 after the verb instead of before", "Using 很 before the object instead of before 喜歡"],
      "repair_feedback": {
        "word_order": "Remember: Subject + 喜歡/不喜歡 + Object. 不 always goes before 喜歡.",
        "politeness": "For polite dislike, use 不太喜歡 instead of 不喜歡.",
        "vocabulary": "Use 喜歡 for like, 不喜歡 for dislike. For stronger dislike, say 不太喜歡."
      }
    },
    {
      "pattern": "Subject + 比較喜歡 + Object1 + (還是 + Object2)",
      "structure": ["Subject", "比較喜歡", "Object1", "(還是 Object2)"],
      "explanation_en": "Use 比較喜歡 to express a preference for one thing over another. Optionally, use 還是 to ask or state a choice between two items.",
      "title": "Expressing Preferences with 比較喜歡",
      "meaning": "To say you prefer something over another",
      "when_to_use": ["When comparing two items, activities, or options", "When answering a question about which you prefer", "When stating a general preference without direct comparison"],
      "when_not_to_use": ["When listing multiple options without comparison (use 喜歡 instead)", "When asking for a choice in a question (use 還是 for questions)"],
      "pragmatic_notes": "In Taiwan, 比較喜歡 is common in daily conversation. For emphasis, use 最喜歡 (like the most). Avoid 比較愛 (prefer to love) as it sounds unnatural.",
      "word_order_notes": "Subject + 比較喜歡 + Object1 + (還是 + Object2). 比較 always comes before 喜歡.",
      "english_contrast": "English uses 'prefer' or 'like more', but Chinese uses 比較喜歡 (literally 'comparatively like'). English often uses 'than', but Chinese uses 還是 for questions or context.",
      "korean_contrast": "Korean uses '더 좋아하다' (deo joahada) for 'prefer', similar to 比較喜歡. Korean uses '보다' (boda) for comparison, while Chinese uses context or 還是.",
      "negative_examples": [
        {
          "text": "我喜歡比較咖啡。",
          "error": "比較 must come before 喜歡, not after. Correct: 我比較喜歡咖啡。"
        },
        {
          "text": "我比較喜歡咖啡比茶。",
          "error": "Chinese doesn't use 比 with 比較喜歡. Use 還是 for questions or context. Correct: 我比較喜歡咖啡，不喜歡茶。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我比較喜歡咖啡很。",
          "error": "很 cannot be placed at the end. If emphasizing, use 我很比較喜歡咖啡 (but this is awkward). Better: 我比較喜歡咖啡。"
        },
        {
          "text": "你比較喜歡茶還是咖啡？我比較喜歡茶還是咖啡。",
          "error": "In answers, don't use 還是. Use 我比較喜歡茶。"
        }
      ],
      "transformation_drills": ["Change '我喜歡喝茶' to show preference over coffee.", "Answer '你比較喜歡甜的還是鹹的？'"],
      "production_drills": ["Say you prefer 紅茶 over 綠茶.", "Ask a friend if they prefer 內用 or 外帶."],
      "common_error_patterns": ["Using 比 with 比較喜歡", "Using 還是 in answers instead of statements"],
      "repair_feedback": {
        "word_order": "Place 比較 before 喜歡: 我比較喜歡...",
        "politeness": "比較喜歡 is polite; for strong preference, use 最喜歡.",
        "vocabulary": "Use 比較喜歡 for preference, 最喜歡 for favorite."
      }
    },
    {
      "pattern": "A 還是 B？ / A 或者 B",
      "structure": ["Option A", "還是/或者", "Option B"],
      "explanation_en": "Use 還是 in questions to ask for a choice between two options. Use 或者 in statements to list alternatives without choosing.",
      "title": "Choosing Between Options: 還是 vs. 或者",
      "meaning": "To ask or state a choice between alternatives",
      "when_to_use": ["Use 還是 in questions when asking someone to choose", "Use 或者 in statements when listing possibilities", "When offering options in a polite question"],
      "when_not_to_use": ["Do not use 或者 in questions", "Do not use 還是 in statements (except in indirect questions)", "When listing more than two options, use 還是 for questions, 或者 for statements"],
      "pragmatic_notes": "In Taiwan, 還是 is very common in daily questions like '你要喝茶還是咖啡？' 或者 is used in statements like '我可以喝茶或者咖啡。' For multiple options, use 還是 between each pair in questions.",
      "word_order_notes": "Option A + 還是/或者 + Option B. No verb needed between options if context is clear.",
      "english_contrast": "English uses 'or' for both questions and statements. Chinese distinguishes: 還是 for questions, 或者 for statements.",
      "korean_contrast": "Korean uses '아니면' (animyeon) for questions (similar to 還是) and '또는' (ttoneun) for statements (similar to 或者).",
      "negative_examples": [
        {
          "text": "你喜歡茶或者咖啡？",
          "error": "Use 還是 in questions, not 或者. Correct: 你喜歡茶還是咖啡？"
        },
        {
          "text": "我可以喝茶還是咖啡。",
          "error": "Use 或者 in statements, not 還是. Correct: 我可以喝茶或者咖啡。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "你喜歡茶還是咖啡嗎？",
          "error": "還是 already implies a question; do not add 嗎. Correct: 你喜歡茶還是咖啡？"
        },
        {
          "text": "我喜歡茶還是咖啡。",
          "error": "還是 cannot be used in a statement. Use 或者 or rephrase. Correct: 我喜歡茶或者咖啡。"
        }
      ],
      "transformation_drills": ["Change '你喜歡茶嗎？' to a choice question with 還是.", "Change '我可以喝茶或咖啡。' to use 或者."],
      "production_drills": ["Ask a friend if they want 冰 or 熱咖啡.", "Say you can eat 飯 or 麵."],
      "common_error_patterns": ["Using 或者 in questions", "Using 還是 in statements", "Adding 嗎 after 還是 questions"],
      "repair_feedback": {
        "word_order": "Place 還是/或者 between the two options.",
        "politeness": "Using 還是 in questions is polite; for very polite offers, add 請問 at the beginning.",
        "vocabulary": "Remember: 還是 for questions, 或者 for statements."
      }
    }
  ]
}
